 4 | export class ToolRunShell extends MicaTool {
 5 |   constructor() {
 6 |     super('run_shell', '执行 shell 命令并返回输出。', {
 7 |       type: 'object' as const,
 8 |       properties: {
 9 |         command: { type: 'string', description: '要执行的命令' },
10 |         timeout: { type: 'number', description: '超时毫秒，默认 30000' },
11 |       },
12 |       required: ['command'],
13 |     });
14 |   }
15 | 
16 |   async execute(input: { command: string; timeout?: number }): Promise<string> {
17 |     return new Promise((resolve) => {
18 |       exec(input.command, {
19 |         encoding: 'utf-8',
20 |         maxBuffer: 5 * 1024 * 1024,
21 |         timeout: input.timeout || 30000,
22 |       }, (error, stdout, stderr) => {
23 |         let output = stdout || '';
24 |         if (stderr) output += (output ? '\n' : '') + stderr;
25 |         const msg = output || '(no output)';
26 |         if (error) {
27 |           const reason = error.killed ? '超时或被终止' : `退出码: ${error.code ?? 'unknown'}`;
28 |           resolve(`(${reason})\n${msg}`);
29 |         } else {
30 |           resolve(msg);
31 |         }
32 |       });
33 |     });
34 |   }
35 | 
36 |   onToolUseDisplayText(input: Record<string, any>): string {
37 |     return `run_shell: ${input.command}`;
38 |   }
39 | }
