27 | export async function executeTool(name: string, input: Record<string, any>): Promise<string> {
28 |   const tool = tools.find((t) => t.name === name);
29 |   if (!tool) return `未知工具: ${name}`;
30 | 
31 |   try {
32 |     return await tool.execute(input);
33 |   } catch (error) {
34 |     const message =
35 |       error instanceof Error
36 |         ? `${error.name}: ${error.message}`
37 |         : typeof error === 'string'
38 |           ? error
39 |           : JSON.stringify(error);
40 |     const maxLen = 2000;
41 |     const truncated = message.length > maxLen ? `${message.slice(0, maxLen)}\n...(截断)` : message;
42 |     return `工具 ${name} 执行失败：\n${truncated}`;
43 |   }
44 | }
45 | export function getToolDisplayText(name: string, input: Record<string, any>): string {
46 |   const tool = tools.find((t) => t.name === name);
47 |   if (!tool) return `未知工具: ${name}`;
48 |   try {
49 |     return tool.onToolUseDisplayText(input);
50 |   } catch (error) {
51 |     const message = error instanceof Error ? `${error.name}: ${error.message}` : String(error);
52 |     return `工具 ${name} onToolUseDisplayText 执行失败：\n${message}`;
53 |   }
54 | }
