  1 | #!/usr/bin/env node
  2 | import Anthropic from '@anthropic-ai/sdk';
  3 | import { systemPrompt } from '../../prompts/index';
  4 | import { executeTool, toolDefinitions } from '../tools/index';
  5 | import { messagesAtom, model, EFFORT_TOKENS, workingStatusAtom } from '../../store/agentAtom.js';
  6 | import { ui } from '../ui/index.js';
  7 | import { MessageStream } from '@anthropic-ai/sdk/lib/MessageStream.mjs';
  8 | import { getClient } from './client';
  9 | import mitt from 'mitt';
 10 | 
 11 | // ── Event types ────────────────────────────────────────
 12 | 
 13 | export type AgentTurnEvents = {
 14 |   'stream:create': MessageStream<null>;
 15 |   'tool:use': {
 16 |     toolUseId: string;
 17 |     toolName: string;
 18 |     toolInput: Record<string, any>;
 19 |     completed: boolean;
 20 |   };
 21 | };
 22 | 
 23 | // ── Public types ───────────────────────────────────────
 24 | 
 25 | export interface IterationResult {
 26 |   hasToolUse: boolean;
 27 |   finalMessage: Anthropic.Message;
 28 | }
 29 | 
 30 | export type RunFn = (
 31 |   userInput: string,
 32 |   onIteration?: (result: IterationResult) => void,
 33 | ) => Promise<void>;
 34 | export type Middleware = (
 35 |   userInput: string,
 36 |   next: RunFn,
 37 |   onIteration?: (result: IterationResult) => void,
 38 | ) => Promise<void>;
 39 | 
 40 | class AgentTurn {
 41 |   /** mitt 事件发射器，替代之前的回调数组 */
 42 |   readonly events = mitt<AgentTurnEvents>();
 43 | 
 44 |   private middlewares: Middleware[] = [];
 45 | 
 46 |   use(middleware: Middleware) {
 47 |     this.middlewares.push(middleware);
 48 |   }
 49 | 
 50 |   async executeSingleIteration(): Promise<IterationResult> {
 51 |     const messages = messagesAtom.get();
 52 |     const modelName = model.atom.get();
 53 |     const effort = model.effort.get();
 54 |     // 通过 UI 组件设置状态
 55 |     ui.WorkingStatus.atomData.set({ type: 'connecting' });
 56 |     ui.MessageBar.emitter.emit('clear');
 57 |     const stream = getClient().messages.stream({
 58 |       model: modelName,
 59 |       max_tokens: model.maxTokens.get(),
 60 |       system: systemPrompt,
 61 |       messages,
 62 |       thinking:
 63 |         effort === 'none'
 64 |           ? { type: 'disabled' as const }
 65 |           : { type: 'enabled' as const, budget_tokens: EFFORT_TOKENS[effort] },
 66 |       output_config: effort !== 'none' ? { effort } : undefined,
 67 |       tools: toolDefinitions,
 68 |     }) as MessageStream<null>;
 69 |     this.events.emit('stream:create', stream);
 70 |     let hasToolUse = false;
 71 |     const completedToolUses: Array<{ id: string; name: string; input: Record<string, any> }> = [];
 72 |     stream.on('contentBlock', (content) => {
 73 |       if (content.type === 'tool_use') {
 74 |         hasToolUse = true;
 75 |         const tool = {
 76 |           id: content.id,
 77 |           name: content.name,
 78 |           input: content.input as Record<string, any>,
 79 |         };
 80 |         completedToolUses.push(tool);
 81 |         this.events.emit('tool:use', {
 82 |           toolUseId: tool.id,
 83 |           toolName: tool.name,
 84 |           toolInput: tool.input,
 85 |           completed: false,
 86 |         });
 87 |       }
 88 |     });
 89 |     // 等待流结束，获取完整消息
 90 |     const finalMessage = await stream.finalMessage();
 91 |     messagesAtom.set([...messages, finalMessage]);
 92 |     // 执行工具并收集结果
 93 |     if (completedToolUses.length > 0) {
 94 |       const toolResults: Anthropic.ToolResultBlockParam[] = [];
 95 |       const settled = await Promise.allSettled(
 96 |         completedToolUses.map((tool) => executeTool(tool.name, tool.input)),
 97 |       );
 98 | 
 99 |       for (let i = 0; i < completedToolUses.length; i++) {
100 |         const tool = completedToolUses[i];
101 |         const r = settled[i];
102 |         const result =
103 |           r.status === 'fulfilled'
104 |             ? r.value
105 |             : `工具 ${tool.name} 执行异常：\n${
106 |                 r.reason instanceof Error
107 |                   ? `${r.reason.name}: ${r.reason.message}`
108 |                   : String(r.reason)
109 |               }`;
110 |         toolResults.push({ type: 'tool_result', tool_use_id: tool.id, content: result });
111 |         this.events.emit('tool:use', {
112 |           toolUseId: tool.id,
113 |           toolName: tool.name,
114 |           toolInput: tool.input,
115 |           completed: true,
116 |         });
117 | 
118 |         // 如果工具执行失败，标记为错误状态
119 |         if (r.status === 'rejected') {
120 |           workingStatusAtom.set({
121 |             type: 'error',
122 |             message: r.reason instanceof Error ? r.reason.message : String(r.reason),
123 |           });
124 |         }
125 |       }
126 | 
127 |       messagesAtom.set([
128 |         ...messagesAtom.get(),
129 |         {
130 |           role: 'user',
131 |           content: toolResults,
132 |         },
133 |       ]);
134 |     }
135 |     workingStatusAtom.set({
136 |       type:'idle'
137 |     })
138 |     return { hasToolUse, finalMessage };
139 |   }
140 |   private async _coreRun(userInput: string, onIteration?: (result: IterationResult) => void) {
141 |     messagesAtom.set([...messagesAtom.get(), { role: 'user', content: userInput }]);
142 |     while (true) {
143 |       const result = await this.executeSingleIteration();
144 |       onIteration?.(result);
145 |       if (!result.hasToolUse) return;
146 |     }
147 |   }
148 | 
149 |   async run(userInput: string, onIteration?: (result: IterationResult) => void) {
150 |     const coreRun: RunFn = this._coreRun.bind(this);
151 |     const chain = this.middlewares.reduceRight<RunFn>(
152 |       (next, mw) => (input, cb) => mw(input, next, cb),
153 |       coreRun,
154 |     );
155 |     return chain(userInput, onIteration);
156 |   }
157 | }
