 1 | import { useEffect, useRef, useState } from 'react';
 2 | import type { ReadableAtom } from 'nanostores';
 3 | import { uuid } from '../../../utils/uuid';
 4 | 
 5 | const THROTTLE_INTERVAL = 16;
 6 | let lastFlushTime = 0;
 7 | let flushTimer: ReturnType<typeof setTimeout> | null = null;
 8 | 
 9 | const pendingUpdaters: Record<string, Function> = {};
10 | 
11 | function flushAll() {
12 |   if (flushTimer) {
13 |     clearTimeout(flushTimer);
14 |     flushTimer = null;
15 |   }
16 |   lastFlushTime = Date.now();
17 |   Object.keys(pendingUpdaters).forEach((key) => {
18 |     pendingUpdaters[key]();
19 |   });
20 | }
21 | 
22 | function scheduleFlush(immediate = false) {
23 |   if (immediate) {
24 |     if (flushTimer) {
25 |       clearTimeout(flushTimer);
26 |       flushTimer = null;
27 |     }
28 |     flushAll();
29 |     return;
30 |   }
31 |   if (flushTimer) return; // 已有排期，等待统一刷新
32 |   const elapsed = Date.now() - lastFlushTime;
33 |   if (elapsed >= THROTTLE_INTERVAL) {
34 |     flushAll();
35 |   } else {
36 |     flushTimer = setTimeout(flushAll, THROTTLE_INTERVAL - elapsed);
37 |   }
38 | }
39 | 
40 | export function useSchedulState<T>(atom: ReadableAtom<T>): T {
41 |   const [state, setState] = useState<T>(atom.get());
42 |   const snapRef = useRef(state);
43 |   const stateUpdaterId = useRef(uuid());
44 |   useEffect(() => {
45 |     const id = stateUpdaterId.current;
46 |             setState(snapRef.current);
47 |     const unsub = atom.subscribe((newState) => {
48 |       snapRef.current = newState;
49 |       pendingUpdaters[id] = () => {
50 |         setState(snapRef.current);
51 |       };
52 |       scheduleFlush();
53 |     });
54 |     return () => {
55 |       unsub();
56 |       delete pendingUpdaters[id];
57 |     };
58 |   }, []);
59 | 
60 |   return state;
61 | }
