  1 | #!/usr/bin/env node
  2 | import Anthropic from '@anthropic-ai/sdk';
  3 | import { systemPrompt } from '../../prompts/index';
  4 | import { executeTool, toolDefinitions } from '../tools/index';
  5 | import { messagesAtom, model, EFFORT_TOKENS, workingStatusAtom, logTextAtom, toolCallsAtom } from '../../store/agentAtom.js';
  6 | import { ui } from '../ui/index.js';
  7 | import { MessageStream } from '@anthropic-ai/sdk/lib/MessageStream.mjs';
  8 | import { getClient } from './client';
  9 | import mitt from 'mitt';
 10 | 
 11 | // ── Event types ────────────────────────────────────────
 12 | 
 13 | export type AgentTurnEvents = {
 14 |   'stream:create': MessageStream<null>;
 15 |   'tool:use': {
 16 |     toolUseId: string;
 17 |     toolName: string;
 18 |     toolInput: Record<string, any>;
 19 |     completed: boolean;
 20 |   };
 21 | };
 22 | 
 23 | // ── Public types ───────────────────────────────────────
 24 | 
 25 | export interface IterationResult {
 26 |   hasToolUse: boolean;
 27 |   finalMessage: Anthropic.Message;
 28 | }
 29 | 
 30 | export type RunFn = (
 31 |   userInput: string,
 32 |   onIteration?: (result: IterationResult) => void,
 33 | ) => Promise<void>;
 34 | export type Middleware = (
 35 |   userInput: string,
 36 |   next: RunFn,
 37 |   onIteration?: (result: IterationResult) => void,
 38 | ) => Promise<void>;
 39 | 
 40 | class AgentTurn {
 41 |   /** mitt 事件发射器，替代之前的回调数组 */
 42 |   readonly events = mitt<AgentTurnEvents>();
 43 | 
 44 |   private middlewares: Middleware[] = [];
 45 | 
 46 |   use(middleware: Middleware) {
 47 |     this.middlewares.push(middleware);
 48 |   }
 49 | 
 50 |   async executeSingleIteration(): Promise<IterationResult> {
 51 |     const messages = messagesAtom.get();
 52 |     const modelName = model.atom.get();
 53 |     const effort = model.effort.get();
 54 |     // 通过 UI 组件设置状态
 55 |     ui.WorkingStatus.atomData.set({ type: 'connecting' });
 56 |     ui.MessageBar.emitter.emit('clear');
 57 |     const stream = getClient().messages.stream({
 58 |       model: modelName,
 59 |       max_tokens: model.maxTokens.get(),
 60 |       system: systemPrompt,
 61 |       messages,
 62 |       thinking:
 63 |         effort === 'none'
 64 |           ? { type: 'disabled' as const }
 65 |           : { type: 'enabled' as const, budget_tokens: EFFORT_TOKENS[effort] },
 66 |       output_config: effort !== 'none' ? { effort } : undefined,
 67 |       tools: toolDefinitions,
 68 |     }) as MessageStream<null>;
 69 |     this.events.emit('stream:create', stream);
 70 |     let hasToolUse = false;
 71 |     const completedToolUses: Array<{ id: string; name: string; input: Record<string, any> }> = [];
 72 |     stream.on('contentBlock', (content) => {
 73 |       if (content.type === 'tool_use') {
 74 |         hasToolUse = true;
 75 |         const tool = {
 76 |           id: content.id,
 77 |           name: content.name,
 78 |           input: content.input as Record<string, any>,
 79 |         };
 80 |         completedToolUses.push(tool);
 81 |         this.events.emit('tool:use', {
 82 |           toolUseId: tool.id,
 83 |           toolName: tool.name,
 84 |           toolInput: tool.input,
 85 |           completed: false,
 86 |         });
 87 |       }
 88 |     });
 89 |     // 等待流结束，获取完整消息
 90 |     const finalMessage = await stream.finalMessage();
 91 |     messagesAtom.set([...messages, finalMessage]);
 92 |     // 执行工具并收集结果
 93 |     if (completedToolUses.length > 0) {
 94 |       const currentCalls = toolCallsAtom.get();
 95 |       for (const tool of completedToolUses) {
 96 |         const idx = currentCalls.findIndex(t => t.id === tool.id);
 97 |         if (idx !== -1) {
 98 |           currentCalls[idx] = { ...currentCalls[idx], status: 'executing' };
 99 |         }
100 |       }
101 |       toolCallsAtom.set([...currentCalls]);
102 | 
103 |       const toolStartTime = Date.now();
104 |       const timer = setInterval(() => {
105 |         const elapsed = Date.now() - toolStartTime;
106 |         workingStatusAtom.set({ type: 'calling_tool', elapsedMs: elapsed });
107 |       }, 200);
108 | 
109 |       const toolResults: Anthropic.ToolResultBlockParam[] = [];
110 |       const settled = await Promise.allSettled(
111 |         completedToolUses.map(async (tool) => {
112 |           const result = await executeTool(tool.name, tool.input, {
113 |             onChunk: (chunk) => {
114 |               const current = logTextAtom.get();
115 |               logTextAtom.set(current + chunk);
116 |             },
117 |           });
118 |           return { tool, result };
119 |         }),
120 |       );
121 | 
122 |       clearInterval(timer);
123 | 
124 |       for (let i = 0; i < settled.length; i++) {
125 |         const item = settled[i];
126 |         const tool = completedToolUses[i];
127 |         const result =
128 |           item.status === 'fulfilled'
129 |             ? item.value.result
130 |             : `工具 ${tool.name} 执行异常：\n${
131 |                 item.reason instanceof Error
132 |                   ? `${item.reason.name}: ${item.reason.message}`
133 |                   : String(item.reason)
134 |               }`;
135 |         toolResults.push({ type: 'tool_result', tool_use_id: tool.id, content: result });
136 |         this.events.emit('tool:use', {
137 |           toolUseId: tool.id,
138 |           toolName: tool.name,
139 |           toolInput: tool.input,
140 |           completed: true,
141 |         });
142 | 
143 |         if (item.status === 'rejected') {
144 |           const calls = toolCallsAtom.get();
145 |           const idx = calls.findIndex(t => t.id === tool.id);
146 |           if (idx !== -1) {
147 |             calls[idx] = { ...calls[idx], status: 'error' };
148 |             toolCallsAtom.set([...calls]);
149 |           }
150 |           workingStatusAtom.set({
151 |             type: 'error',
152 |             message: item.reason instanceof Error ? item.reason.message : String(item.reason),
153 |           });
154 |         }
155 |       }
156 | 
157 |       messagesAtom.set([
158 |         ...messagesAtom.get(),
159 |         {
160 |           role: 'user',
161 |           content: toolResults,
162 |         },
163 |       ]);
164 |     }
165 |     workingStatusAtom.set({
166 |       type:'idle'
167 |     })
168 |     return { hasToolUse, finalMessage };
169 |   }
170 |   private async _coreRun(userInput: string, onIteration?: (result: IterationResult) => void) {
171 |     messagesAtom.set([...messagesAtom.get(), { role: 'user', content: userInput }]);
172 |     while (true) {
173 |       const result = await this.executeSingleIteration();
174 |       onIteration?.(result);
175 |       if (!result.hasToolUse) return;
176 |     }
177 |   }
178 | 
179 |   async run(userInput: string, onIteration?: (result: IterationResult) => void) {
180 |     const coreRun: RunFn = this._coreRun.bind(this);
181 |     const chain = this.middlewares.reduceRight<RunFn>(
182 |       (next, mw) => (input, cb) => mw(input, next, cb),
183 |       coreRun,
184 |     );
185 |     return chain(userInput, onIteration);
186 |   }
187 | }
188 | 
189 | export const agentTurn = new AgentTurn();
