 1 | import { spawn } from 'child_process';
 2 | import { MicaTool, ToolExecuteCallbacks } from './MicaTool';
 3 | 
 4 | export class ToolRunShell extends MicaTool {
 5 |   constructor() {
 6 |     super('run_shell', '执行 shell 命令并返回输出。', {
 7 |       type: 'object' as const,
 8 |       properties: {
 9 |         command: { type: 'string', description: '要执行的命令' },
10 |         timeout: { type: 'number', description: '超时毫秒，默认 30000' },
11 |       },
12 |       required: ['command'],
13 |     });
14 |   }
15 | 
16 |   async execute(input: { command: string; timeout?: number }, callbacks?: ToolExecuteCallbacks): Promise<string> {
17 |     const timeout = input.timeout || 30000;
18 | 
19 |     return new Promise((resolve) => {
20 |       const child = spawn(input.command, {
21 |         shell: true,
22 |         timeout,
23 |         stdio: ['ignore', 'pipe', 'pipe'],
24 |       });
25 | 
26 |       let output = '';
27 | 
28 |       child.stdout.on('data', (data: Buffer) => {
29 |         const chunk = data.toString();
30 |         output += chunk;
31 |         callbacks?.onChunk?.(chunk);
32 |       });
33 | 
34 |       child.stderr.on('data', (data: Buffer) => {
35 |         const chunk = data.toString();
36 |         output += chunk;
37 |         callbacks?.onChunk?.(chunk);
38 |       });
39 | 
40 |       child.on('close', (code) => {
41 |         const msg = output || '(no output)';
42 |         if (code !== 0 && code !== null) {
43 |           resolve(`(退出码: ${code})\n${msg}`);
44 |         } else {
45 |           resolve(msg);
46 |         }
47 |       });
48 | 
49 |       child.on('error', (error) => {
50 |         if (output) {
51 |           resolve(`(错误: ${error.message})\n${output}`);
52 |         } else {
53 |           resolve(`(错误: ${error.message})`);
54 |         }
55 |       });
56 |     });
57 |   }
58 | 
59 |   onToolUseDisplayText(input: Record<string, any>): string {
60 |     return `run_shell: ${input.command}`;
61 |   }
62 | }
